import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

import polygonClipping from 'polygon-clipping';

import AnnotationTopBar from '../components/AnnotationTopBar';
import AnnotationCanvas from '../components/AnnotationCanvas';
import AnnotationListSidebar from '../components/AnnotationListSidebar';
import './Annotate.css';

export default function Annotate() {
  const navigate = useNavigate();
  const { state } = useLocation();
  const folderInfo = state?.folderInfo;

  if (!folderInfo) {
    return (
      <div style={{ padding: 20 }}>
        <h2>No folder info found. Please create a task first.</h2>
        <button onClick={() => navigate('/')}>Go Home</button>
      </div>
    );
  }

  const { folderId, taskName, labelClasses, files } = folderInfo;

  // -------------- Annotations for each image --------------
  const [annotations, setAnnotations] = useState({});
  const [undoStack, setUndoStack] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  // Tools: move, bbox, polygon, polyline, point, ellipse, segmentation
  // default to 'move'
  const [selectedTool, setSelectedTool] = useState('move');

  // For “segmentation” specifically, we have a small dropdown (Instance, Semantic, Panoptic)
  const [segmentationType, setSegmentationType] = useState('instance');

  const [selectedLabelClass, setSelectedLabelClass] = useState(
    labelClasses[0]?.name || ''
  );
  const [scale, setScale] = useState(1.0);

  const currentFileUrl = files[currentIndex]?.url;
  const currentShapes = annotations[currentFileUrl] || [];

  // Whenever shapes change, store old state in undoStack
  const handleAnnotationsChange = (newShapes) => {
    const updated = {
      ...annotations,
      [currentFileUrl]: newShapes,
    };
    setUndoStack([...undoStack, annotations]);
    setRedoStack([]);
    setAnnotations(updated);
  };

  // -------------- Undo / Redo --------------
  const undo = () => {
    if (undoStack.length === 0) return;
    const prev = undoStack[undoStack.length - 1];
    setRedoStack([...redoStack, annotations]);
    setUndoStack(undoStack.slice(0, -1));
    setAnnotations(prev);
  };

  const redo = () => {
    if (redoStack.length === 0) return;
    const next = redoStack[redoStack.length - 1];
    setUndoStack([...undoStack, annotations]);
    setRedoStack(redoStack.slice(0, -1));
    setAnnotations(next);
  };

  // -------------- Deletion & Update --------------
  const handleDeleteAnnotation = (index) => {
    const arr = [...currentShapes];
    arr.splice(index, 1);
    handleAnnotationsChange(arr);
  };

  const handleUpdateAnnotation = (index, changes) => {
    const arr = [...currentShapes];
    arr[index] = { ...arr[index], ...changes };
    handleAnnotationsChange(arr);
  };

  // -------------- Navigation --------------
  const handlePrev = () => {
    if (currentIndex > 0) setCurrentIndex((i) => i - 1);
  };
  const handleNext = () => {
    if (currentIndex < files.length - 1) setCurrentIndex((i) => i + 1);
  };

  // -------------- Zoom --------------
  const handleZoomIn = () => setScale((s) => Math.min(s + 0.1, 5));
  const handleZoomOut = () => setScale((s) => Math.max(s - 0.1, 0.2));
  const handleWheelZoom = (deltaY) => {
    if (deltaY < 0) handleZoomIn();
    else handleZoomOut();
  };

  // -------------- Save --------------
  const handleSave = async () => {
    const bodyData = {
      folderId,
      taskName,
      labelClasses,
      annotations,
    };
    try {
      const res = await fetch('http://localhost:4000/api/annotations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bodyData),
      });
      const data = await res.json();
      alert('Saved: ' + data.message);
    } catch (err) {
      console.error(err);
      alert('Error saving');
    }
  };

  // -------------- Keyboard Shortcuts --------------
  useEffect(() => {
    const handleKey = (e) => {
      const key = e.key;

      // Tools
      if (key === 'm' || key === 'M') {
        setSelectedTool('move');
      } else if (key === 'b' || key === 'B') {
        setSelectedTool('bbox');
      } else if (key === 'p' || key === 'P') {
        setSelectedTool('polygon');
      } else if (key === 'l' || key === 'L') {
        setSelectedTool('polyline');
      } else if (key === 'o' || key === 'O') {
        setSelectedTool('point');
      } else if (key === 'e' || key === 'E') {
        setSelectedTool('ellipse');
      }
      // Segmentation on plain "S"
      else if ((key === 's' || key === 'S') && e.ctrlKey) {
        // Ctrl+S => Save
        e.preventDefault();
        handleSave();
      } else if (key === 's' || key === 'S') {
        // Just S => Segmentation
        setSelectedTool('segmentation');
      }

      // Esc => cancel shape
      if (key === 'Escape') {
        const event = new CustomEvent('cancel-annotation');
        window.dispatchEvent(event);
      }
      // Next / Prev
      if (key === 'ArrowRight') {
        handleNext();
      } else if (key === 'ArrowLeft') {
        handlePrev();
      }

      // Undo / Redo
      if (e.ctrlKey && (key === 'z' || key === 'Z')) {
        e.preventDefault();
        undo();
      } else if (e.ctrlKey && (key === 'y' || key === 'Y')) {
        e.preventDefault();
        redo();
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
    // eslint-disable-next-line
  }, [annotations, undoStack, redoStack]);

  // -------------- Export Logic --------------
  const [exportOpen, setExportOpen] = useState(false);
  const openExport = () => setExportOpen(true);
  const closeExport = () => setExportOpen(false);

  const exportAnnotations = (format) => {
    if (format === 'coco') {
      downloadCOCO();
    } else if (format === 'yolo') {
      downloadYOLO();
    } else if (format === 'pascal') {
      downloadPascal();
    }
    closeExport();
  };

  function downloadFile(url, filename) {
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }

  function downloadCOCO() {
    alert('COCO export not yet implemented!');
  }
  function downloadYOLO() {
    alert('YOLO export not yet implemented!');
  }
  function downloadPascal() {
    alert('Pascal VOC export not yet implemented!');
  }

  // -------------- When annotation finishes => switch to move --------------
  const handleFinishShape = () => {
    setSelectedTool('move');
  };

  // --------------- Fill Background ------------------------------------
  // Small color palette in case black (#000000) is taken
  const backgroundColorPalette = [
    '#000000', // default black
    '#0072ff',
    '#00d100',
    '#ff00ff',
    '#ff7f00',
    '#808080',
    '#ffff00',
    '#00ffff',
  ];

  // Utility to get a background color that isn’t already used
  function getBackgroundColor(existingLabelClasses) {
    const usedColors = existingLabelClasses.map((lc) => lc.color?.toLowerCase() || '');
    for (let c of backgroundColorPalette) {
      if (!usedColors.includes(c.toLowerCase())) {
        return c;
      }
    }
    // fallback
    return '#000000';
  }

  // ----------- Fill Background Logic -----------
  const handleFillBackground = async () => {
    // If no current shapes, do nothing
    if (!currentShapes.length || !currentFileUrl) return;

    // 1) Remove any existing background annotation for this image
    const existingBgIndex = (annotations[currentFileUrl] || []).findIndex(a => a.type === 'background');
    let existingShapes = [...currentShapes];
    if (existingBgIndex !== -1) {
      existingShapes.splice(existingBgIndex, 1);
    }

    // 2) Construct bounding polygon for the entire image
    // We do not know the raw image width/height from 'annotate.js' directly.
    // So we assume each file has width/height in 'files' array. If not available,
    // you will need to pass in real image dims from the server or from the canvas.
    // Below we assume `files[currentIndex]` has `width` and `height`.
    const imgW = files[currentIndex]?.width || 0;
    const imgH = files[currentIndex]?.height || 0;
    if (imgW <= 0 || imgH <= 0) {
      alert('Image dimensions not found. Cannot fill background.');
      return;
    }
    // polygon-clipping format => array of polygons => each polygon = array of rings => each ring = array of [x, y]
    // Full image rect:
    let backgroundPoly = [
      [
        [[0, 0], [imgW, 0], [imgW, imgH], [0, imgH], [0, 0]]
      ]
    ];

    // 3) For each annotation (bbox or polygon), compute a polygon shape and subtract it from backgroundPoly
    const unionSubtract = (shapePoly) => {
      // Do difference: backgroundPoly = difference(backgroundPoly, shapePoly)
      if (!shapePoly || !shapePoly.length) return;
      backgroundPoly = polygonClipping.difference(backgroundPoly, shapePoly);
      // difference() can return null or an empty array if everything is subtracted
      if (!backgroundPoly || !backgroundPoly.length) {
        backgroundPoly = [];
      }
    };

    // Helper: convert a bbox to polygon
    const bboxToPoly = (bbox) => {
      const x1 = bbox.x;
      const y1 = bbox.y;
      const x2 = bbox.x + bbox.width;
      const y2 = bbox.y + bbox.height;
      return [
        [
          [[x1, y1], [x2, y1], [x2, y2], [x1, y2], [x1, y1]]
        ]
      ];
    };

    // Helper: convert "polygon" annotation points => polygon-clipping format
    const polygonToPoly = (annPoints) => {
      if (!annPoints || annPoints.length < 3) return null;
      const ring = annPoints.map(pt => [pt.x, pt.y]);
      // close it
      ring.push([annPoints[0].x, annPoints[0].y]);
      return [[[...ring]]];
    };

    // Subtract each relevant shape from backgroundPoly
    for (let ann of existingShapes) {
      if (ann.type === 'bbox') {
        unionSubtract(bboxToPoly(ann));
      }
      else if (ann.type === 'polygon') {
        const p = polygonToPoly(ann.points);
        if (p) unionSubtract(p);
      }
      // ignoring ellipse, polyline, point, etc. You can adapt similarly if you want them subtracted
    }

    if (!backgroundPoly || !backgroundPoly.length) {
      alert('Background is fully covered or no valid area left.');
      return;
    }

    // 4) Merge or create a background labelClass
    let bgLabel = labelClasses.find(lc => lc.name === 'background');
    if (!bgLabel) {
      // pick color
      const colorToUse = getBackgroundColor(labelClasses);
      bgLabel = {
        name: 'background',
        color: colorToUse
      };
      labelClasses.push(bgLabel);
    }

    // 5) Create a single "background" annotation with multi polygons
    // We'll store each polygonClipping geometry as a ring array
    // shape = { type: 'background', multi: [ [ [x,y], [x2,y2], ...], [...], ... ], label: 'background', color: '#000' }
    // "backgroundPoly" can be an array of polygons, each polygon can have multiple rings, but for holes we'll rely on even-odd fill.
    // Flatten them into a top-level array of rings.
    let multi = [];
    // polygonClipping format => array of Polygons => each polygon = array of rings => each ring = array of [x,y]
    backgroundPoly.forEach((poly) => {
      poly.forEach((ring) => {
        multi.push(ring);
      });
    });

    if (!multi.length) {
      alert('No background area to fill.');
      return;
    }

    // 6) Add final background annotation
    const backgroundAnn = {
      type: 'background',
      multi, // store array-of-rings
      label: bgLabel.name,
      color: bgLabel.color,
    };

    const newShapes = [...existingShapes, backgroundAnn];
    handleAnnotationsChange(newShapes);
  };


  return (
    <div className="annotate-container">
      <AnnotationTopBar
        onHome={() => navigate('/')}
        onPrev={handlePrev}
        onNext={handleNext}
        onSave={handleSave}
        onZoomIn={handleZoomIn}
        onZoomOut={handleZoomOut}
        onExport={openExport}
        currentIndex={currentIndex}
        total={files.length}
        taskName={taskName}
      />

      <div style={{ padding: '8px', background: '#eee' }}>
        <button onClick={undo} style={{ marginRight: '8px' }}>
          Undo (Ctrl+Z)
        </button>
        <button onClick={redo} style={{ marginRight: '8px' }}>
          Redo (Ctrl+Y)
        </button>
        <button
          onClick={handleFillBackground}
          disabled={currentShapes.length === 0}
          style={{ marginRight: '8px' }}
        >
          Fill Background
        </button>
      </div>

      <div className="annotate-main">
        {/* Tools Sidebar */}
        <div className="tools-sidebar">
          <h3>Tools</h3>
          <label>
            <input
              type="radio"
              name="tool"
              value="move"
              checked={selectedTool === 'move'}
              onChange={() => setSelectedTool('move')}
            />
            <span className="tool-icon">👆</span> Move (M)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="bbox"
              checked={selectedTool === 'bbox'}
              onChange={() => setSelectedTool('bbox')}
            />
            <span className="tool-icon">⬛</span> BBox (B)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polygon"
              checked={selectedTool === 'polygon'}
              onChange={() => setSelectedTool('polygon')}
            />
            <span className="tool-icon">🔺</span> Polygon (P)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="polyline"
              checked={selectedTool === 'polyline'}
              onChange={() => setSelectedTool('polyline')}
            />
            <span className="tool-icon">📈</span> Polyline (L)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="point"
              checked={selectedTool === 'point'}
              onChange={() => setSelectedTool('point')}
            />
            <span className="tool-icon">📍</span> Point (O)
          </label>
          <label>
            <input
              type="radio"
              name="tool"
              value="ellipse"
              checked={selectedTool === 'ellipse'}
              onChange={() => setSelectedTool('ellipse')}
            />
            <span className="tool-icon">⬭</span> Ellipse (E)
          </label>

          {/* Segmentation */}
          <label>
            <input
              type="radio"
              name="tool"
              value="segmentation"
              checked={selectedTool === 'segmentation'}
              onChange={() => setSelectedTool('segmentation')}
            />
            <span className="tool-icon">🎨</span> Segmentation (S)
          </label>
          {selectedTool === 'segmentation' && (
            <div style={{ marginLeft: '20px', marginBottom: '8px' }}>
              <label style={{ display: 'block', marginBottom: '4px' }}>
                Type:
              </label>
              <select
                value={segmentationType}
                onChange={(e) => setSegmentationType(e.target.value)}
              >
                <option value="instance">Instance</option>
                <option value="semantic">Semantic</option>
                <option value="panoptic">Panoptic</option>
              </select>
            </div>
          )}

          <h3 style={{ marginTop: 16 }}>Active Label</h3>
          <select
            value={selectedLabelClass}
            onChange={(e) => setSelectedLabelClass(e.target.value)}
          >
            {labelClasses.map((lc, i) => (
              <option key={i} value={lc.name}>
                {lc.name}
              </option>
            ))}
          </select>

          <div className="note-area">
            <p><strong>Shortcuts:</strong></p>
            <ul>
              <li>M/B/P/L/O/E => Tools</li>
              <li>S => Segmentation</li>
              <li>Ctrl+S => Save</li>
              <li>Esc => Cancel shape</li>
              <li>ArrowLeft => Prev image</li>
              <li>ArrowRight => Next image</li>
              <li>Ctrl+Z => Undo</li>
              <li>Ctrl+Y => Redo</li>
              <li>Ctrl+C => Copy selected</li>
              <li>Ctrl+V => Paste annotation</li>
            </ul>
          </div>
        </div>

        {/* Canvas */}
        <div className="canvas-area">
          {currentFileUrl ? (
            <AnnotationCanvas
              fileUrl={currentFileUrl}
              annotations={currentShapes}
              onAnnotationsChange={handleAnnotationsChange}
              selectedTool={selectedTool}
              scale={scale}
              onWheelZoom={handleWheelZoom}
              activeLabelColor={
                labelClasses.find((l) => l.name === selectedLabelClass)?.color ||
                '#ff0000'
              }
              onFinishShape={handleFinishShape}
              onDeleteAnnotation={handleDeleteAnnotation}
              activeLabel={selectedLabelClass}
              labelClasses={labelClasses}
              // Pass segmentationType to the canvas
              segmentationType={segmentationType}
            />
          ) : (
            <div style={{ textAlign: 'center', margin: 'auto' }}>
              No images found
            </div>
          )}
        </div>

        <AnnotationListSidebar
          annotations={currentShapes}
          onDeleteAnnotation={handleDeleteAnnotation}
          onUpdateAnnotation={handleUpdateAnnotation}
          labelClasses={labelClasses}
        />
      </div>

      {exportOpen && (
        <div className="export-modal-backdrop">
          <div className="export-modal">
            <h2>Export Annotations</h2>
            <p>Select format:</p>
            <div className="export-buttons">
              <button onClick={() => exportAnnotations('coco')}>COCO</button>
              <button onClick={() => exportAnnotations('yolo')}>YOLO</button>
              <button onClick={() => exportAnnotations('pascal')}>Pascal VOC</button>
            </div>
            <button className="close-btn" onClick={closeExport}>
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
